#include <bits/stdc++.h>
using namespace std;

const int MOD = 1e9 + 7;
const int MAXN = 100005;

long long dp[MAXN][8];

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);

    int n;
    cin >> n;

    // Initialize DP array
    memset(dp, 0, sizeof(dp));
    dp[0][0] = 1;

    // Process each position in the circle
    for (int i = 0; i < 3 * n; ++i) {
        for (int j = 0; j < 8; ++j) {
            if (dp[i][j] == 0) continue;

            // Determine the coins at positions i-n, i, and i+n
            int coin_i_n = j % 3;
            int coin_i = (j / 3) % 3;
            int coin_i_2n = (j / 9) % 3;

            // Check the condition for the triplet (i, i+n, i+2n)
            bool valid = true;
            if ((coin_i + coin_i_n + coin_i_2n) == 6) {
                valid = false;
            }

            // Transition to the next position
            for (int next_coin_i_1 = 1; next_coin_i_1 <= 3; ++next_coin_i_1) {
                for (int next_coin_i_2 = 1; next_coin_i_2 <= 3; ++next_coin_i_2) {
                    for (int next_coin_i_3 = 1; next_coin_i_3 <= 3; ++next_coin_i_3) {
                        int next_j = next_coin_i_3 * 9 + next_coin_i_2 * 3 + next_coin_i_1;
                        if (!valid && next_coin_i_1 == 2 && next_coin_i_2 == 2 && next_coin_i_3 == 2) {
                            continue;
                        }
                        dp[(i + 1) % (3 * n)][next_j] = (dp[(i + 1) % (3 * n)][next_j] + dp[i][j]) % MOD;
                    }
                }
            }
        }
    }

    // Sum up all valid states at the end
    long long result = 0;
    for (int j = 0; j < 8; ++j) {
        result = (result + dp[(3 * n - 1) % (3 * n)][j]) % MOD;
    }

    cout << result << endl;

    return 0;
}

