class Solver {
  struct Edge {
    int to, w, ne;
  };
  vector<Edge> es;
  vector<int> firs;
  vector<int> was;
  int wver;
  int en;

  bool dfs(int v) {
    if (v == en) return true;
    if (was[v] >= wver) return false;
    was[v] = wver;
    for (int i = firs[v]; i >= 0; i = es[i].ne) {
      if (es[i].w > 0) {
        if (dfs(es[i].to)) {
          es[i].w--;
          es[i ^ 1].w++;
          return true;
        }
      }
    }
    return false;
  }

public:
  Solver() : wver(0) {}
  void reset(int n) {
    es.clear();
    firs.assign(n, -1);
    was.resize(n);
  }
  void adde(int a, int b, int w) {
    es.pb({b, w, firs[a]});
    firs[a] = (int)es.size() - 1;
    es.pb({a, 0, firs[b]});
    firs[b] = (int)es.size() - 1;
  }
  int solve_aux(int st, int _en) {
    en = _en;
    int res = 0;
    for (;;) {
      wver++;
      if (!dfs(st)) break;
      res++;
    }
    return res;
  }
};

void solve() {
  int n, m;
  while (cin >> n >> m) {
    vector<int> as(n);
    for (int i = 0; i < n; i++) cin >> as[i];

    vector<pair<int, int>> goods(m);
    for (int i = 0; i < m; i++) {
      cin >> goods[i].first >> goods[i].second;
      goods[i].first--, goods[i].second--;
      if (goods[i].first & 1) {
        swap(goods[i].first, goods[i].second);
      }
    }

    map<int, vector<pair<int, int>>> byPs;
    for (int i = 0; i < n; i++) {
      int x = as[i];
      for (int i2 = 2; i2 * i2 <= x; i2++) {
        int cdeg = 0;
        while (x % i2 == 0) {
          x /= i2;
          cdeg++;
        }
        if (cdeg) byPs[i2].pb({i, cdeg});
      }
      if (x > 1) {
        byPs[x].pb({i, 1});
      }
    }

    int ans = 0;
    Solver s;

    for (const auto &_curp : byPs) {
      const vector<pair<int, int>> &nums = _curp.second;

      vector<int> myId(n, -1);
      for (int i = 0; i < (int)nums.size(); i++) {
        myId[nums[i].first] = i;
      }

      s.reset((int)nums.size() + 2);
      const int st = (int)nums.size(), en = (int)nums.size() + 1;
      for (auto e : goods) {
        int a = myId[e.first];
        int b = myId[e.second];
        if (a < 0 || b < 0) continue;
        s.adde(a, b, 30);
      }
      for (int a = 0; a < (int)nums.size(); a++) {
        if ((nums[a].first & 1) == 0) {
          s.adde(st, a, nums[a].second);
        } else {
          s.adde(a, en, nums[a].second);
        }
      }
      ans += s.solve_aux(st, en);
    }
    cout << ans << '\n';
  }
}

int main() {
  fastio;
  solve();
  return 0;
}

