    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int maxOperations(vector<int>& a, vector<vector<int>>& pairs) {
    int n = a.size();
    int m = pairs.size();
    int totalOperations = 0;

    for (const auto& p : pairs) {
        int i = p[0] - 1;
        int j = p[1] - 1;
        int g = gcd(a[i], a[j]);
        if (g > 1) {
            int op = 0;
            while (a[i] % g == 0 && a[j] % g == 0) {
                a[i] /= g;
                a[j] /= g;
                ++op;
            }
            totalOperations += op;
        }
    }

    return totalOperations;
}

