vll f, inv;
ll M = 998244353;

ll comb(ll n, ll k) {
    if (k < 0 || k > n) return 0;
    return f[n] * inv[n - k] % M * inv[k] % M;
}

void solve() {
    ll n, k;
    cin >> n >> k;
    vll h(n);
    for (ll i = 0; i < n; ++i) {
        cin >> h[i];
    }

    ll m = 0;
    for (ll i = 0; i < n; ++i) {
        if (h[i] != h[(i + 1) % n]) {
            ++m;
        }
    }

    f.assign(m + 1, 0);
    f[0] = 1;
    for (ll i = 1; i <= m; ++i) {
        f[i] = f[i - 1] * i % M;
    }

    inv.assign(m + 1, 0);
    inv[m] = modpw(f[m], M - 2, M);
    for (ll i = m; i >= 1; --i) {
        inv[i - 1] = inv[i] * i % M;
    }

    ll A = modpw(k, m, M);
    ll B = 0;
    ll base = (k - 2) % M;
    if (base < 0) base += M;
    for (ll i = 0; i <= m / 2; ++i) {
        ll term = comb(m, i) * comb(m - i, i) % M;
        term = term * modpw(base, m - 2 * i, M) % M;
        B = (B + term) % M;
    }

    ll C = modpw(k, n - m, M);
    ll D = modpw(2, M - 2, M);

    ll ans = (A - B) % M;
    if (ans < 0) ans += M;
    ans = ans * C % M;
    ans = ans * D % M;
    ans = (ans % M + M) % M;

    cout << ans << endl;
}

