#include <iostream>
#include <vector>
using namespace std;

const int MOD = 998244353;

int solve(int n, int k, vector<int>& h) {
    vector<vector<int>> dp(n + 1, vector<int>(n + 1, 0));
    dp[0][0] = 1;

    for (int i = 1; i <= n; ++i) {
        for (int j = 0; j <= n; ++j) {
            for (int a = 1; a <= k; ++a) {
                int next_pos = (i % n) + 1;
                int new_score = (j + (a == h[next_pos])) % n;
                dp[i][new_score] = (dp[i][new_score] + dp[i-1][j]) % MOD;
            }
        }
    }

    // Sum up all valid states where the new score is greater than the old score
    int result = 0;
    for (int j = 0; j < n; ++j) {
        for (int a = 1; a <= k; ++a) {
            int next_pos = (j % n) + 1;
            int new_score = (j + (a == h[next_pos])) % n;
            if (new_score > j) {
                result = (result + dp[j][j]) % MOD;
            }
        }
    }

    return result;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, k;
    cin >> n >> k;
    vector<int> h(n);
    for (int i = 0; i < n; ++i) {
        cin >> h[i];
    }

    cout << solve(n, k, h) << endl;

    return 0;
}

