void solve() {
    int n, k;
    cin >> n >> k;
    vector<long long> a(n);
    for (int i = 0; i < n; ++i)
        cin >> a[i];

    sort(a.begin(), a.end());

    long long min_val = a[0];
    for (int i = 0; i < k; ++i) {
        // Find the maximum gap
        long long max_gap = 0;
        for (int j = 1; j < n; ++j)
            max_gap = max(max_gap, a[j] - a[j - 1]);

        // Reduce the maximum gap by half
        long long mid = max_gap / 2;
        for (int j = 1; j < n; ++j)
            a[j] -= mid;

        // Update the minimum value
        min_val = *min_element(a.begin(), a.end());
    }

    cout << min_val << endl;
}

