#include <algorithm>

using namespace std;

struct Passenger {
    int floor;
    int time;
};

bool compare(const Passenger& a, const Passenger& b) {
    return a.time < b.time;
}

int minTimeToFloorZero(int n, int s, vector<Passenger>& passengers) {
    sort(passengers.begin(), passengers.end(), compare);

    int currentTime = 0;
    int currentFloor = s;

    for (const auto& passenger : passengers) {
        int passengerArrivalTime = passenger.time;
        int passengerFloor = passenger.floor;

        // Wait for passenger to arrive
        currentTime = max(currentTime, passengerArrivalTime);

        // Move down to the passenger's floor
        if (currentFloor > passengerFloor) {
            currentTime += (currentFloor - passengerFloor);
            currentFloor = passengerFloor;
        }

        // Pick up passenger (no time cost)

        // Move down to floor 0
        currentTime += (currentFloor - 0);
        currentFloor = 0;
    }

    return currentTime;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, s;
    cin >> n >> s;

    vector<Passenger> passengers(n);
    for (int i = 0; i < n; ++i) {
        cin >> passengers[i].floor >> passengers[i].time;
    }

    cout << minTimeToFloorZero(n, s, passengers) << endl;

    return 0;
}

