using namespace std;

#define ll long long
#define vi vector<int>
#define vl vector<ll>
#define vb vector<bool>
#define vvi vector<vi>
#define vvl vector<vl>
#define pii pair<int,int>
#define pll pair<ll,ll>
#define piii tuple<int,int,int>
#define pq priority_queue
#define pb push_back
#define pf push_front
#define mp make_pair
#define F first
#define S second
#define sz(x) ((int)(x).size())
#define all(x) (x).begin(),(x).end()
#define rall(x) (x).rbegin(),(x).rend()

const int N = 26;
vvi dp(N, vi(N));
vector<vector<pii>> paths;
map<ll, vector<pii>> costs;

void dfs(int x, int y, int len, vvi &path) {
    if (len == 2 * N - 2) {
        paths.pb(path);
        costs[dp[x][y]].pb(path.back());
        return;
    }
    if (x < N - 1) {
        path.pb({x + 1, y});
        dfs(x + 1, y, len + 1, path);
        path.pop_back();
    }
    if (y < N - 1) {
        path.pb({x, y + 1});
        dfs(x, y + 1, len + 1, path);
        path.pop_back();
    }
}

void init_dp() {
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            dp[i][j] = i + j;
        }
    }
    for (int i = 1; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            dp[i][j] += dp[i - 1][j];
        }
    }
    for (int i = 0; i < N; ++i) {
        for (int j = 1; j < N; ++j) {
            dp[i][j] += dp[i][j - 1];
        }
    }
}

void solve() {
    int n;
    cin >> n;
    init_dp();
    vvi path;
    dfs(0, 0, 0, path);

    int q;
    cin >> q;
    while (q--) {
        ll k;
        cin >> k;
        auto &p = costs[k].back();
        for (auto [x, y] : p) {
            cout << x + 1 << " " << y + 1 << "\n";
        }
        cout << endl;
        costs[k].pop_back();
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    solve();
    return 0;
}

