#include <iostream>
#include <vector>
#include <unordered_set>
#include <queue>

using namespace std;

void dfs(const vector<vector<int>>& adj, vector<bool>& visited, int node) {
    queue<int> q;
    q.push(node);
    visited[node] = true;

    while (!q.empty()) {
        int current = q.front();
        q.pop();

        for (int neighbor : adj[current]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                q.push(neighbor);
            }
        }
    }
}

vector<vector<int>> find_components(const vector<vector<int>>& adj, int n) {
    vector<bool> visited(n + 1, false);
    vector<vector<int>> components;

    for (int i = 1; i <= n; ++i) {
        if (!visited[i]) {
            vector<int> comp;
            dfs(adj, visited, i);
            for (int j = 1; j <= n; ++j) {
                if (visited[j]) {
                    comp.push_back(j);
                }
            }
            components.push_back(comp);
        }
    }

    return components;
}

vector<unordered_set<int>> get_component_edges(const vector<vector<int>>& adj, const vector<vector<int>>& components) {
    vector<unordered_set<int>> component_edges(components.size());

    for (const auto& edge : adj) {
        int u = edge[0], v = edge[1];
        for (size_t i = 0; i < components.size(); ++i) {
            if (components[i].count(u) && components[i].count(v)) {
                component_edges[i].insert(edge[0]);
                component_edges[i].insert(edge[1]);
                break;
            }
        }
    }

    return component_edges;
}

bool is_valid_edge(const vector<unordered_set<int>>& component_edges, size_t u_comp, size_t v_comp, int u, int v) {
    if (u_comp == v_comp) {
        return component_edges[u_comp].find(u) != component_edges[u_comp].end() &&
               component_edges[v_comp].find(v) != component_edges[v_comp].end();
    } else {
        return true;
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m1, m2;
    cin >> n >> m1 >> m2;

    vector<vector<int>> mocha_adj(n + 1);
    vector<vector<int>> diana_adj(n + 1);

    for (int i = 0; i < m1; ++i) {
        int u, v;
        cin >> u >> v;
        mocha_adj[u].push_back(v);
        mocha_adj[v].push_back(u);
    }

    for (int i = 0; i < m2; ++i) {
        int u, v;
        cin >> u >> v;
        diana_adj[u].push_back(v);
        diana_adj[v].push_back(u);
    }

    auto mocha_components = find_components(mocha_adj, n);
    auto diana_components = find_components(diana_adj, n);

    vector<unordered_set<int>> mocha_component_edges = get_component_edges(mocha_adj, mocha_components);
    vector<unordered_set<int>> diana_component_edges = get_component_edges(diana_adj, diana_components);

    unordered_set<string> used_edges;
    vector<pair<int, int>> result;

    for (size_t i = 0; i < mocha_components.size(); ++i) {
        for (size_t j = 0; j < diana_components.size(); ++j) {
            if (i == j) {
                for (int u : mocha_components[i]) {
                    for (int v : mocha_components[j]) {
                        string edge_str = to_string(min(u, v)) + "-" + to_string(max(u, v));
                        if (used_edges.count(edge_str) == 0 &&
                            is_valid_edge(mocha_component_edges, i, j, u, v) &&
                            is_valid_edge(diana_component_edges, i, j, u, v)) {
                            used_edges.insert(edge_str);
                            result.emplace_back(u, v);
                        }
                    }
                }
            } else {
                for (int u : mocha_components[i]) {
                    for (int v : diana_components[j]) {
                        string edge_str = to_string(min(u, v)) + "-" + to_string(max(u, v));
                        if (used_edges.count(edge_str) == 0 &&
                            is_valid_edge(mocha_component_edges, i, j, u, v) &&
                            is_valid_edge(diana_component_edges, i, j, u, v)) {
                            used_edges.insert(edge_str);
                            result.emplace_back(u, v);
                        }
                    }
                }
            }
        }
    }

    cout << result.size() << '\n';
    for (const auto& edge : result) {
        cout << edge.first << ' ' << edge.second << '\n';
    }

    return 0;
}

