using namespace std;

int solve(const vector<int>& a, int n, int k) {
    vector<int> prefix(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix[i + 1] = prefix[i] + (a[i] == i + 1);
    }

    auto query = [&](int l, int r) {
        return prefix[r] - prefix[l];
    };

    int left = 0, right = n;
    while (left < right) {
        int mid = (left + right) / 2;
        bool found = false;
        for (int start = 0; start <= n - mid; ++start) {
            int end = start + mid;
            if (query(start, end) >= k) {
                found = true;
                break;
            }
        }
        if (found) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }
    return left;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n, k;
        cin >> n >> k;
        vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            cin >> a[i];
        }
        cout << solve(a, n, k) << '\n';
