int solve(int n, int m, vector<int>& b, vector<int>& g) {
    // Check if there's any conflict
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            if (b[i] > g[j]) {
                return -1;
            }
        }
    }

    // Initialize assignment matrix
    vector<vector<bool>> assigned(n, vector<bool>(m, false));

    // Iterate over boys and assign sweets
    for (int i = 0; i < n; ++i) {
        int remaining = b[i];
        for (int j = 0; j < m && remaining > 0; ++j) {
            if (!assigned[i][j] && g[j] >= remaining) {
                assigned[i][j] = true;
                remaining -= remaining;
            }
        }
        if (remaining > 0) {
            return -1; // Conflict detected
        }
    }

    // Calculate total sweets
    long long total_sweets = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            if (assigned[i][j]) {
                total_sweets += b[i];
            }
        }
    }

    return static_cast<int>(total_sweets);
}

