// Li Chao Tree for maximum of lines y = m*x + b
struct Line {
    ll m, b;
    Line(ll _m = 0, ll _b = -4e18) : m(_m), b(_b) {}
    ll eval(ll x) const { return m * x + b; }
};

struct LiChaoTree {
    static const ll MIN_X = -1000000;
    static const ll MAX_X = 1000000;
    struct Node {
        Line line;
        Node *left, *right;
        Node() : line(0, -4e18), left(nullptr), right(nullptr) {}
    };
    Node* root;
    LiChaoTree() { root = new Node(); }

    void insert(Node* &u, ll l, ll r, Line newLine) {
        if (!u) {
            u = new Node();
            u->line = newLine;
            return;
        }
        ll mid = l + (r - l) / 2;
        bool leftBetter = newLine.eval(l) > u->line.eval(l);
        bool midBetter = newLine.eval(mid) > u->line.eval(mid);
        if (midBetter) {
            swap(u->line, newLine);
        }
        if (l == r) return;
        if (leftBetter != midBetter) {
            insert(u->left, l, mid, newLine);
        } else {
            insert(u->right, mid + 1, r, newLine);
        }
    }

    void insert(Line line) {
        insert(root, MIN_X, MAX_X, line);
    }

    ll query(Node* u, ll l, ll r, ll x) {
        if (!u) return -4e18;
        ll res = u->line.eval(x);
        if (l == r) return res;
        ll mid = l + (r - l) / 2;
        if (x <= mid) {
            return max(res, query(u->left, l, mid, x));
        } else {
            return max(res, query(u->right, mid + 1, r, x));
        }
    }

    ll query(ll x) {
        return query(root, MIN_X, MAX_X, x);
    }
};

void solve() {
    int n;
    cin >> n;
    vll a(n + 1);
    for (int i = 1; i <= n; ++i) cin >> a[i];
    vll pref(n + 1, 0);
    for (int i = 1; i <= n; ++i) pref[i] = pref[i - 1] + a[i];
    ll orig = 0;
    for (int i = 1; i <= n; ++i) orig += a[i] * i;
    ll ans = orig;

    // pass 1: move right (i < j)
    LiChaoTree tree1;
    for (int i = n; i >= 1; --i) {
        if (i < n) {
            ll best = tree1.query(a[i]);
            ll delta = best - (a[i] * i - pref[i]);
            ans = max(ans, orig + delta);
        }
        tree1.insert(Line(i, -pref[i]));
    }

    // pass 2: move left (i > j)
    LiChaoTree tree2;
    for (int i = 1; i <= n; ++i) {
        if (i > 1) {
            ll best = tree2.query(a[i]);
            ll delta = best - (a[i] * i - pref[i - 1]);
            ans = max(ans, orig + delta);
        }
        tree2.insert(Line(i, -pref[i - 1]));
    }

    cout << ans << '\n';
}

int main() {
    fastio;
    solve();
    return 0;
}

