        long long rightContribution = (prefixSum[n] - prefixSum[i]) * (n - i);

        // Total contribution of moving to position 1
        long long totalGain = leftContribution - rightContribution;
        maxGain = max(maxGain, totalGain);

        // Check moving to position n+1
        long long nextTotalGain = leftContribution + rightContribution;
        maxGain = max(maxGain, nextTotalGain);

        // Check moving to other positions
        for (int j = 1; j <= n; ++j) {
            if (j == i + 1 || j == n) continue;
            long long gain = a[i] * (j - i);
            maxGain = max(maxGain, gain);
        }
    }

    return c0 + maxGain;
}

