void solve(int n, int k, string &result) {
    if (n == 0) return;

    // Total permutations left if we fix the current position as 'a'
    int count_a_prefix = n * (n - 1) / 2;

    // If k <= count_a_prefix, the current character is 'a'
    if (k <= count_a_prefix) {
        result += 'a';
        solve(n - 1, k, result);
