int solve(vector<int>& a) {
    int n = a.size();
    int ans = 0;

    // Iterate from the largest piece to the smallest
    for (int i = n - 1; i > 0; --i) {
        int x = a[i];
        int lo = 0, hi = x / 2;

        // Binary search to find the minimum cuts needed
        while (lo < hi) {
            int mid = (lo + hi) / 2;
            int min_piece = a[0];
            bool valid = true;

            for (int j = 1; j <= i; ++j) {
                int y = max(min_piece, a[j] - mid);
                int z = a[j] - y;
                if (2 * min_piece > y || 2 * y > z) {
                    valid = false;
                    break;
                }
            }

            if (valid) {
                hi = mid;
            } else {
                lo = mid + 1;
            }
        }

        ans += lo;
    }

    return ans;
}

