using namespace std;

pair<int, int> solve(int t1, int t2, int x1, int x2, int t0) {
    int best_y1 = 0, best_y2 = 0;
    double min_error = 1e9;

    for (int y1 = 0; y1 <= x1; ++y1) {
        // Calculate the required y2 to achieve the target temperature t0
        double numerator = static_cast<double>(t1 * y1 - t0 * y1);
        double denominator = static_cast<double>(t0 - t2);

        if (denominator == 0) {
            // Special case when t0 == t2, any y2 within bounds works
            for (int y2 = 0; y2 <= x2; ++y2) {
                double t = static_cast<double>(t1 * y1 + t2 * y2) / (y1 + y2);
                if (t >= t0 && abs(t - t0) < min_error) {
                    min_error = abs(t - t0);
                    best_y1 = y1;
                    best_y2 = y2;
                }
            }
        } else {
            int y2 = static_cast<int>(numerator / denominator);
            if (y2 >= 0 && y2 <= x2) {
                double t = static_cast<double>(t1 * y1 + t2 * y2) / (y1 + y2);
                if (t >= t0 && abs(t - t0) < min_error) {
                    min_error = abs(t - t0);
                    best_y1 = y1;
                    best_y2 = y2;
                }
            }
        }
    }

    return {best_y1, best_y2};
}

