struct Alarm {
    int hour;
    int minute;
};

bool operator<(const Alarm& a, const Alarm& b) {
    if (a.hour == b.hour) return a.minute < b.minute;
    return a.hour < b.hour;
}

pair<int, int> timeDiff(int startHour, int startMinute, int endHour, int endMinute) {
    int startTotal = startHour * 60 + startMinute;
    int endTotal = endHour * 60 + endMinute;
    int diff = (endTotal - startTotal + 24 * 60) % (24 * 60);
    int hours = diff / 60;
    int minutes = diff % 60;
    return {hours, minutes};
}

