        for (int i = 0; i < n; ++i) {
            cin >> alarms[i].hour >> alarms[i].minute;
        }

        sort(alarms.begin(), alarms.end());

        bool found = false;
        for (const auto& alarm : alarms) {
            if (alarm.hour > H || (alarm.hour == H && alarm.minute >= M)) {
                cout << timeDiff(H, M, alarm.hour, alarm.minute) << endl;
