long long gcd(long long a, long long b) {
    while (b != 0) {
        long long temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

long long lcm(long long a, long long b) {
    return a / gcd(a, b) * b;
}

bool check(long long mid, int x, int y, int k) {
    long long total = mid;
    long long removed = 0;

    for (int i = 1; i <= x; ++i) {
        long long base = i * y;
        if (base > mid) break;
        long long count = (mid - base + 1) / base;
        removed += count;
    }

    return total - removed >= k;
}

void solve(int x, int y, int k) {
    long long left = 1, right = 1e12;
    long long result = -1;

    while (left <= right) {
        long long mid = left + (right - left) / 2;
        if (check(mid, x, y, k)) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    cout << result << endl;
}

