bool is_prime(int x) {
    if (x <= 1) return false;
    for (int i = 2; i <= sqrt(x); ++i) {
        if (x % i == 0) return false;
    }
    return true;
}

void sieve(vector<bool>& prime, int max_n) {
    prime.assign(max_n + 1, true);
    prime[0] = prime[1] = false;
    for (int i = 2; i * i <= max_n; ++i) {
        if (prime[i]) {
            for (int j = i * i; j <= max_n; j += i) {
                prime[j] = false;
            }
        }
    }
}

vector<int> get_primes_up_to_n(int n) {
    vector<bool> prime;
    sieve(prime, 2 * n);
    vector<int> primes;
    for (int i = 2; i <= 2 * n; ++i) {
        if (prime[i]) {
            primes.push_back(i);
        }
    }
    return primes;
}

void solve() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    vector<int> primes = get_primes_up_to_n(n);
    vector<pair<int, int>> ops;
    bool swapped = true;
    while (swapped) {
        swapped = false;
        for (int i = 0; i < n; ++i) {
            if (a[i] != i + 1) {
                for (auto p : primes) {
                    if (i + p > n) break;
                    if (a[i + p] == i + 1) {
                        swap(a[i], a[i + p]);
                        ops.emplace_back(i + 1, i + p + 1);
                        swapped = true;
                        break;
                    }
                }
            }
        }
    }

    cout << ops.size() << '\n';
    for (const auto& op : ops) {
        cout << op.first << ' ' << op.second << '\n';
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    solve();
    return 0;
}

