pair<int, char> dfs(const string& s, int i, int j) {
    if (visited[i][j]) return {dp[i][j], 'X'};
    visited[i][j] = true;

    if (i == j - 1) {
        dp[i][j] = 1;
        return {'a', 'a'}; // Alice wins
    }

    pair<int, char> take_first = dfs(s, i + 1, j);
    pair<int, char> take_last = dfs(s, i, j - 1);

    if (take_first.first > take_last.first) {
        dp[i][j] = take_first.first;
        return {take_first.first, s[i]};
    } else if (take_first.first < take_last.first) {
        dp[i][j] = take_last.first;
        return {take_last.first, s[j-1]};
    } else {
        dp[i][j] = take_first.first;
        return {take_first.first, min(s[i], s[j-1])};
    }
}

