using namespace std;

void solve(int n, vector<pair<int, int>>& pairs) {
    vector<int> perm(n + 1);
    vector<bool> used(n * n);

    auto try_pair = [&](int i, int j) -> bool {
        if (used[i * n + j]) return false;
        used[i * n + j] = true;
        perm[i] = j;
        return true;
    };

    auto find_next = [&](int curr) {
        for (auto& [a, b] : pairs) {
            if (perm[curr] == a && !used[a * n + b]) {
                return b;
            }
            if (perm[curr] == b && !used[b * n + a]) {
                return a;
            }
        }
        return -1;
    };

    for (int start = 1; start <= n; ++start) {
        if (!try_pair(start, find_next(start))) continue;

        int prev = start;
        while (true) {
            int next = find_next(prev);
            if (next == start) break;
            if (!try_pair(prev, next)) {
                fill(perm.begin(), perm.end(), 0);
                break;
            }
            prev = next;
        }

        if (perm[start] != 0) {
            for (int i = 1; i <= n; ++i) cout << perm[i] << " ";
            cout << endl;
            return;
        }
    }
}

