enum Type {
  AND,
  OR,
  XOR,
  NOT,
  IN
};

vector<Type> types;
vector<vll> g;
vll val;
vll val_changed;
vll parent;

ll dfs(ll v, ll p) {
  parent[v] = p;
  if (types[v] == IN) {
    return val[v];
  }
  if (types[v] == NOT) {
    return val[v] = !dfs(g[v][0], v);
  }
  if (types[v] == AND) {
    return val[v] = dfs(g[v][0], v) & dfs(g[v][1], v);
  }
  if (types[v] == OR) {
    return val[v] = dfs(g[v][0], v) | dfs(g[v][1], v);
  }
  if (types[v] == XOR) {
    return val[v] = dfs(g[v][0], v) ^ dfs(g[v][1], v);
  }
  return 0;
}

void dfs_ans(ll v) {
  if (v == 0) {
    val_changed[v] = val[v] ^ 1;
  } else {
    ll p = parent[v];
    ll new_val = (val[v] ^ 1);
    if (types[p] == NOT) {
      val_changed[v] = val_changed[p];
    } else {
      ll diff_val = ((g[p][0] == v) ? val[g[p][1]] : val[g[p][0]]);
      ll parent_val = val[p];
      if (types[p] == AND) {
        parent_val = diff_val & new_val;
      }
      if (types[p] == OR) {
        parent_val = diff_val | new_val;
      }
      if (types[p] == XOR) {
        parent_val = diff_val ^ new_val;
      }
      if (parent_val != val[p]) {
        val_changed[v] = val_changed[p];
      } else {
        val_changed[v] = val[0];
      }
    }
  }
  for (ll to : g[v]) {
    dfs_ans(to);
  }
}

void solve() {
  ll n;
  cin >> n;
  types.resize(n);
  g.clear();
  g.resize(n);
  val.resize(n);
  for (ll i = 0; i < n; ++i) {
    string s;
    cin >> s;
    if (s == "IN") {
      types[i] = IN;
      cin >> val[i];
    } else if (s == "NOT") {
      types[i] = NOT;
      ll cur;
      cin >> cur;
      --cur;
      g[i].pb(cur);
    } else {
      switch(s[0]) {
        case 'A':
          types[i] = AND;
          break;
        case 'O':
          types[i] = OR;
          break;
        case 'X':
          types[i] = XOR;
          break;
        default:
          assert(false);
      }
      g[i].resize(2);
      for (ll j = 0; j < 2; ++j) {
        cin >> g[i][j];
        --g[i][j];
      }
    }
  }
  parent.resize(n);
  dfs(0, 0);
  val_changed.resize(n);
  dfs_ans(0);

  for (ll i = 0; i < n; ++i) {
    if (types[i] == IN) {
      cout << val_changed[i];
    }
  }
  cout << "\n";
}

int main() {
  fastio;
  int t = 1;
  while (t--) {
    solve();
  }
  return 0;
}

