#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
using namespace std;

void solve(int n, int k, const string& s, vector<int>& result) {
    vector<vector<int>> dp(k + 1, vector<int>(2, 0));

    // Initial lengths without changes
    int l0 = 0, l1 = 0;
    for (char c : s) {
        if (c == '0') {
            l0++;
            l1 = max(l1, l0);
        } else {
            l1++;
            l0 = max(l0, l1);
        }
    }

    // Binary search over number of changes
    for (int a = 1; a <= n; ++a) {
        int ans = 0;
        for (int i = 0; i <= k; ++i) {
            ans = max(ans, a * dp[i][0] + dp[i][1]);
        }
        result.push_back(ans);

        // Update DP table
        for (int i = k; i >= 1; --i) {
            dp[i][0] = max(dp[i][0], dp[i-1][0] + 1);
            dp[i][1] = max(dp[i][1], dp[i-1][1] + 1);
        }
        dp[0][0] = 0;
        dp[0][1] = 0;
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n, k;
        cin >> n >> k;
        string s;
        cin >> s;

        vector<int> result;
        solve(n, k, s, result);

        for (int val : result) {
            cout << val << " ";
        }
        cout << endl;
    }

    return 0;
}

