const int MAXN = 200005;
bool dp[MAXN][MAXN];
int n;

bool check(int i, int j, const string& a, const string& b) {
    if (i == n / 2 && j == n / 2)
        return true;
    if (dp[i][j])
        return true;

    // Try the first split
    bool first_split = (a.substr(i, n / 2) == b.substr(j, n / 2)) &&
                       check(i + n / 2, j + n / 2, a, b);

    // Try the second split
    bool second_split = (a.substr(i, n / 2) == b.substr(j + n / 2, n / 2)) &&
                        (a.substr(i + n / 2, n / 2) == b.substr(j, n / 2));

    dp[i][j] = first_split || second_split;
    return dp[i][j];
}

