    cin >> a >> b;
    n = a.size();

    if (a == b) {
        cout << "YES\n";
        return 0;
    }

    memset(dp, false, sizeof(dp));
    if (check(0, 0, a, b))
        cout << "YES\n";
    else
        cout << "NO\n";

    return 0;
